/* FPS Counter — top right corner */
#hud::after {
  content: attr(data-fps);
  position: absolute;
  top: calc(12px + env(safe-area-inset-top, 0px));
  right: calc(12px + env(safe-area-inset-right, 0px));
  font-family: 'PressStart2P', monospace;
  font-size: 12px;
  color: white;
  text-shadow: 1px 1px 2px black;
  z-index: 1001;
  pointer-events: none;
}
